import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import Navbar from '../components/shared/Navbar';
import { providerAPI, bookingAPI } from '../utils/api';
import { format, addDays } from 'date-fns';
import toast from 'react-hot-toast';

const TIME_SLOTS = ['08:00 AM','09:00 AM','10:00 AM','11:00 AM','12:00 PM','01:00 PM','02:00 PM','03:00 PM','04:00 PM','05:00 PM','06:00 PM'];

export default function BookingPage() {
  const { providerId } = useParams();
  const navigate = useNavigate();
  const [provider, setProvider] = useState(null);
  const [loading, setLoading] = useState(true);
  const [submitting, setSubmitting] = useState(false);
  const [form, setForm] = useState({
    skillRequired: '',
    description: '',
    date: format(addDays(new Date(), 1), 'yyyy-MM-dd'),
    time: '10:00 AM',
    address: '',
    addressLat: '',
    addressLng: '',
  });

  useEffect(() => {
    providerAPI.getById(providerId)
      .then(r => { setProvider(r.data.data); setForm(f => ({ ...f, skillRequired: r.data.data.skills?.[0] || '' })); })
      .catch(() => toast.error('Provider not found'))
      .finally(() => setLoading(false));

    // Try to get user's address from browser
    navigator.geolocation?.getCurrentPosition(({ coords }) => {
      setForm(f => ({ ...f, addressLat: coords.latitude, addressLng: coords.longitude }));
    });
  }, [providerId]);

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!form.skillRequired) return toast.error('Please select a skill/service');
    if (!form.address.trim()) return toast.error('Please enter your address');
    setSubmitting(true);
    try {
      const { data } = await bookingAPI.create({
        provider: providerId,
        skillRequired: form.skillRequired,
        description: form.description,
        scheduledDate: form.date,
        scheduledTime: form.time,
        address: { text: form.address, lat: form.addressLat || undefined, lng: form.addressLng || undefined },
      });
      toast.success('Booking request sent! Waiting for provider confirmation.');
      navigate(`/bookings/${data.data._id}`);
    } catch (err) {
      toast.error(err.response?.data?.message || 'Booking failed');
    } finally {
      setSubmitting(false);
    }
  };

  if (loading) return <div><Navbar /><div className="page-container" style={{ paddingTop: 40 }}><div className="spinner" /></div></div>;
  if (!provider) return null;

  const u = provider.user || {};
  const next7Days = Array.from({ length: 7 }, (_, i) => addDays(new Date(), i + 1));

  return (
    <div style={{ minHeight: '100vh' }}>
      <Navbar />
      <div className="page-container" style={{ paddingTop: 32, paddingBottom: 48, maxWidth: 800 }}>
        <button className="btn btn-ghost btn-sm" style={{ marginBottom: 20 }} onClick={() => navigate(-1)}>← Back</button>

        <h1 style={{ fontSize: 26, fontWeight: 800, marginBottom: 4 }}>Book a Service</h1>
        <p style={{ color: 'var(--text-secondary)', marginBottom: 28, fontSize: 14 }}>Fill in the details to request this provider</p>

        {/* Provider summary */}
        <div className="card" style={{ display: 'flex', gap: 16, alignItems: 'center', marginBottom: 24 }}>
          <div style={{ width: 52, height: 52, borderRadius: '50%', background: 'var(--accent-dim)', display: 'flex', alignItems: 'center', justifyContent: 'center', color: 'var(--accent)', fontWeight: 800, fontSize: 18 }}>
            {u.name?.split(' ').map(n => n[0]).join('').slice(0, 2)}
          </div>
          <div style={{ flex: 1 }}>
            <div style={{ fontWeight: 700 }}>{u.name}</div>
            <div style={{ fontSize: 13, color: 'var(--text-secondary)' }}>{provider.serviceCategory} • {provider.experience}y exp</div>
          </div>
          <div style={{ textAlign: 'right' }}>
            <div style={{ fontSize: 18, fontWeight: 800, fontFamily: 'var(--font-display)', color: 'var(--success)' }}>₹{provider.priceRange?.min}–{provider.priceRange?.max}</div>
            <div style={{ fontSize: 12, color: 'var(--text-muted)' }}>Estimated price</div>
          </div>
        </div>

        <form onSubmit={handleSubmit}>
          <div className="card" style={{ marginBottom: 20 }}>
            <h3 style={{ fontWeight: 700, marginBottom: 16, fontSize: 15 }}>Service Details</h3>

            <div className="form-group" style={{ marginBottom: 14 }}>
              <label className="form-label">Select Service Required *</label>
              <div style={{ display: 'flex', flexWrap: 'wrap', gap: 8 }}>
                {provider.skills?.map(skill => (
                  <button key={skill} type="button"
                    className={`btn btn-sm ${form.skillRequired === skill ? 'btn-primary' : 'btn-ghost'}`}
                    onClick={() => setForm(f => ({ ...f, skillRequired: skill }))}>
                    {skill}
                  </button>
                ))}
              </div>
            </div>

            <div className="form-group">
              <label className="form-label">Problem Description</label>
              <textarea className="form-textarea" placeholder="Describe your problem in detail... e.g. The ceiling fan is making a noise and not working at full speed." value={form.description} onChange={e => setForm(f => ({ ...f, description: e.target.value }))} />
            </div>
          </div>

          <div className="card" style={{ marginBottom: 20 }}>
            <h3 style={{ fontWeight: 700, marginBottom: 16, fontSize: 15 }}>Schedule</h3>

            {/* Date selection */}
            <div className="form-group" style={{ marginBottom: 14 }}>
              <label className="form-label">Select Date *</label>
              <div style={{ display: 'flex', gap: 8, flexWrap: 'wrap' }}>
                {next7Days.map(d => {
                  const val = format(d, 'yyyy-MM-dd');
                  return (
                    <button key={val} type="button"
                      className={`btn btn-sm ${form.date === val ? 'btn-primary' : 'btn-ghost'}`}
                      onClick={() => setForm(f => ({ ...f, date: val }))}>
                      <div style={{ textAlign: 'center' }}>
                        <div style={{ fontSize: 10, opacity: 0.7 }}>{format(d, 'EEE')}</div>
                        <div>{format(d, 'd MMM')}</div>
                      </div>
                    </button>
                  );
                })}
              </div>
            </div>

            {/* Time selection */}
            <div className="form-group">
              <label className="form-label">Select Time *</label>
              <div style={{ display: 'flex', gap: 8, flexWrap: 'wrap' }}>
                {TIME_SLOTS.map(t => (
                  <button key={t} type="button"
                    className={`btn btn-sm ${form.time === t ? 'btn-primary' : 'btn-ghost'}`}
                    onClick={() => setForm(f => ({ ...f, time: t }))}>
                    {t}
                  </button>
                ))}
              </div>
            </div>
          </div>

          <div className="card" style={{ marginBottom: 24 }}>
            <h3 style={{ fontWeight: 700, marginBottom: 16, fontSize: 15 }}>Service Address</h3>
            <div className="form-group">
              <label className="form-label">Full Address *</label>
              <textarea className="form-textarea" style={{ minHeight: 70 }}
                placeholder="e.g. Flat 304, Sunrise Apartments, Anna Nagar, Chennai - 600040"
                value={form.address} onChange={e => setForm(f => ({ ...f, address: e.target.value }))} required />
            </div>
          </div>

          {/* Summary */}
          <div style={{ background: 'var(--bg-secondary)', border: '1px solid var(--border)', borderRadius: 'var(--radius)', padding: 16, marginBottom: 24 }}>
            <h4 style={{ fontWeight: 700, marginBottom: 12, fontSize: 14 }}>Booking Summary</h4>
            <div style={{ display: 'flex', flexDirection: 'column', gap: 8, fontSize: 13 }}>
              {[
                ['Provider', u.name],
                ['Service', form.skillRequired || '—'],
                ['Date & Time', form.date && form.time ? `${format(new Date(form.date), 'EEE, d MMM yyyy')} at ${form.time}` : '—'],
                ['Est. Price', `₹${provider.priceRange?.min} – ₹${provider.priceRange?.max}`],
              ].map(([label, value]) => (
                <div key={label} style={{ display: 'flex', justifyContent: 'space-between' }}>
                  <span style={{ color: 'var(--text-muted)' }}>{label}</span>
                  <span style={{ fontWeight: 500 }}>{value}</span>
                </div>
              ))}
            </div>
          </div>

          <button className="btn btn-primary btn-lg" type="submit" disabled={submitting} style={{ width: '100%' }}>
            {submitting ? 'Sending Request...' : '📅 Send Booking Request'}
          </button>
          <p style={{ textAlign: 'center', color: 'var(--text-muted)', fontSize: 12, marginTop: 10 }}>
            The provider will confirm or reject your request. No payment now.
          </p>
        </form>
      </div>
    </div>
  );
}
